class Solution(object):
    def deleteGreatestValue(self, grid):
        for row in grid:
            row.sort()
        result = 0
        for col in range(len(grid[0])):
            max_val = 0
            for row in range(len(grid)):
                max_val = max(max_val, grid[row][col])
            result += max_val
        return result
